;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

roof = events.has(3) ? "hot" : "stone"

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] true

@delevent
@wait time=500
@notice text="When I stepped onto the new floor, I was immediately struck by a wave of intense heat that was clearly different from before!"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@notice text="The scorching heat from the boiling lava assails us! We can't move forward like this."
@walk move=s

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] WAY == "n" && onUseEventItem && curItem == o.氷竜の心臓

@delevent
@delevent num=2
@notice text="We threw the Ice Dragon's heart into the lava in front of us!"
@btmes off
@wait time=1000
@flash on=1000
@eval exp='game.map.changeFloorsOfWideArea(%[type: "floor", img: "soild", trap: void], 0, 2, 4, 16)'
@eval exp='game.map.roof = "stone"'
@eval exp='game.map.effect = void'
@eval exp='game.view.setEnvironmentInfo(game.map)'
@eval exp='game.updateView()'
@wait time=1000
@flash off=1000
@wait time=1000
@notice text="The lava cooled and formed black lumps!"

[eventoff]
;-------------------------------------------------------------------------------
